class Solution {
public:
    vector<vector<int>> largeGroupPositions(string s) {
        vector<vector<int>> result;
        int start = 0;
        for (int end = 1; end <= s.length(); ++end) {
            if (end == s.length() || s[end] != s[start]) {
                if (end - start >= 3) {
                    result.push_back({start, end - 1});
                }
                start = end;
            }
        }
        return result;
    }
};
